/* ---------- RUN METADATA BLOCK (Overview tab) ---------- */

/** Format a path-like value for compact display: keep just the basename. */
function shortenPath(v) {
  if (!v || typeof v !== "string") return v;
  if (v.includes("/")) return v.slice(v.lastIndexOf("/") + 1);
  if (v.includes("\\")) return v.slice(v.lastIndexOf("\\") + 1);
  return v;
}

const RunMetadataBlock = ({ meta }) => {
  // Run parameters are useful but not essential after first glance —
  // collapsible, but expanded by default so first-time viewers see them.
  const [open, setOpen] = useState(true);
  // Choose which fields to show, in this order, with friendly labels.
  // Optional `format(value)` lets a field clean up the raw string (e.g.
  // strip a trailing ".0" so "25.0" → "25").
  const formatInt = (v) => {
    const n = parseFloat(v);
    return Number.isFinite(n) && Number.isInteger(n) ? String(n) : v;
  };
  const displayFields = [
    { key: "crocodeel version", label: "CroCoDeEL version" },
    { key: "datetime", label: "Run date" },
    { key: "rf_model", label: "RF model", shorten: true },
    { key: "probability_cutoff", label: "Probability cutoff" },
    { key: "rate_cutoff", label: "Rate cutoff" },
    {
      key: "filtering_ab_thr_factor",
      label: "Abundance filter",
      // Always visible, even when CroCoDeEL was run without
      // --filter-low-ab. We surface "0" in that case so the reader knows
      // the run did NOT apply any low-abundance trimming, rather than
      // silently dropping the field.
      alwaysShow: true,
      format: (v) => (!v || v === "None" ? "0" : formatInt(v)),
    },
    { key: "username", label: "User" },
    { key: "hostname", label: "Host" },
  ];
  const items = displayFields
    .map((f) => {
      let v = meta[f.key];
      if (v && f.shorten) v = shortenPath(v);
      if (f.format) v = f.format(v);
      return {
        label: f.label,
        hint: f.hint,
        value: v || null,
        raw: meta[f.key],
        alwaysShow: !!f.alwaysShow,
      };
    })
    .filter((it) => it.alwaysShow || (it.value && it.value !== "None"));

  if (items.length === 0) return null;

  return (
    <div
      className="mt-4 p-4 rounded-sm"
      style={{
        background: "var(--bg-soft)",
        border: "1px solid var(--border)",
        borderLeft: "4px solid #00a3a6",
      }}
    >
      <button
        type="button"
        onClick={() => setOpen((v) => !v)}
        className="flex items-center gap-1.5 text-[10px] tracking-[0.15em] uppercase mb-2"
        style={{
          background: "transparent",
          border: 0,
          padding: 0,
          cursor: "pointer",
          color: "#ed6e6c",
          fontWeight: 700,
          fontFamily: '"Raleway", sans-serif',
        }}
        aria-expanded={open}
      >
        {open ? (
          <ChevronDown className="w-3 h-3" />
        ) : (
          <ChevronRight className="w-3 h-3" />
        )}
        Run parameters
      </button>
      {open && (
      <dl
        className="grid gap-x-6 gap-y-1.5"
        style={{ gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))" }}
      >
        {items.map((it) => (
          <div
            key={it.label}
            className="flex items-baseline gap-2 text-[12px]"
            style={{ minWidth: 0 }}
          >
            <dt
              className="shrink-0"
              title={it.hint || undefined}
              style={{
                color: "var(--ink-muted)",
                fontWeight: 600,
                fontFamily: '"Raleway", sans-serif',
                cursor: it.hint ? "help" : undefined,
                textDecoration: it.hint ? "underline dotted" : undefined,
                textUnderlineOffset: 2,
              }}
            >
              {it.label}:
            </dt>
            <dd
              title={it.raw !== it.value ? it.raw : undefined}
              className="truncate"
              style={{
                color: "var(--ink)",
                fontFamily: "system-ui, monospace",
                fontWeight: 500,
              }}
            >
              {it.value}
            </dd>
          </div>
        ))}
      </dl>
      )}
    </div>
  );
};

const Overview = ({ counts, events, hasAb, metadata, plateMap, runMetadata, onOpen, onLoadDemo, demoLoading, actionEnabled }) => {
  const topByScore = [...events].sort((a, b) => b.score - a.score).slice(0, 5);
  const topByRate = [...events].sort((a, b) => b.rate - a.rate).slice(0, 5);
  const bottomByScore = [...events].sort((a, b) => a.score - b.score).slice(0, 5);
  const bottomByRate = [...events].sort((a, b) => a.rate - b.rate).slice(0, 5);
  const eventsWithIntroduced = events.filter((e) => e.introducedPct != null);
  const topByIntroduced = [...eventsWithIntroduced]
    .sort((a, b) => b.introducedPct - a.introducedPct)
    .slice(0, 5);
  const bottomByIntroduced = [...eventsWithIntroduced]
    .sort((a, b) => a.introducedPct - b.introducedPct)
    .slice(0, 5);
  const noData = events.length === 0;

  const relatedCount = useMemo(() => {
    if (!metadata) return null;
    return events.filter((e) => areRelated(metadata, e.source, e.target)?.related === true).length;
  }, [events, metadata]);

  const adjacentCount = useMemo(() => {
    if (!plateMap) return null;
    return events.filter((e) => {
      const pd = plateDistance(plateMap, e.source, e.target);
      return pd && pd.samePlate && pd.distance != null && pd.distance <= 1;
    }).length;
  }, [events, plateMap]);

  const cascadeCount = events.filter((e) => e.cascade).length;

  // Suppress / keep counts. Use the same default-resolution rules as
  // the rest of the app: TP -> suppress, FP -> keep, others -> none.
  // Only meaningful when the feature is enabled.
  const { keepCount, suppressCount } = useMemo(() => {
    let keep = 0;
    let supp = 0;
    if (actionEnabled) {
      events.forEach((e) => {
        const a =
          e.action ||
          (e.verdict === "true_positive"
            ? "suppress"
            : e.verdict === "false_positive"
              ? "keep"
              : null);
        if (a === "keep") keep++;
        else if (a === "suppress") supp++;
      });
    }
    return { keepCount: keep, suppressCount: supp };
  }, [events, actionEnabled]);

  // Number of connected components in the contamination network — gives
  // a sense of how clustered the events are.
  const componentCount = useMemo(
    () => (events.length === 0 ? 0 : buildComponents(events).length),
    [events],
  );

  // Number of samples annotated in the metadata file (null when none
  // loaded). Useful to compare against `samples involved` to see what
  // fraction of the dataset has context.
  const annotatedCount = useMemo(() => {
    if (!metadata) return null;
    return Object.keys(metadata.bySample || {}).length;
  }, [metadata]);

  const avgIntroducedPct =
    eventsWithIntroduced.length > 0
      ? eventsWithIntroduced.reduce((s, e) => s + e.introducedPct, 0) /
        eventsWithIntroduced.length
      : null;

  return (
    <div>
      <SectionTitle eyebrow="Overview" title="Your analysis at a glance">
        These are the events CroCoDeEL flagged. Your role: distinguish real contamination
        from coincidental abundance similarity. Start from the highest-probability events.
      </SectionTitle>

      {/* No-data banner — shown until the user uploads contamination_events.tsv */}
      {noData && (
        <div
          className="mt-2 mb-8 p-5 rounded-sm flex items-center gap-5 flex-wrap"
          style={{
            background: "var(--bg-info)",
            border: "1px solid #00a3a6",
            borderLeft: "4px solid #00a3a6",
          }}
        >
          <div className="flex-1 min-w-[260px]">
            <div
              className="text-[14px]"
              style={{
                color: "var(--ink)",
                fontWeight: 700,
                fontFamily: '"Raleway", sans-serif',
              }}
            >
              No data loaded yet
            </div>
            <div
              className="text-[12px] mt-1"
              style={{ color: "var(--ink-muted)", lineHeight: 1.5 }}
            >
              Open your{" "}
              <code style={{ fontFamily: "ui-monospace, monospace" }}>
                contamination_events.tsv
              </code>{" "}
              from the cards at the top of the page, or load the bundled
              demo dataset (
              <a
                href="https://doi.org/10.1186/s40168-023-01477-2"
                target="_blank"
                rel="noopener noreferrer"
                style={{
                  color: "#00a3a6",
                  textDecoration: "underline",
                  textUnderlineOffset: 2,
                }}
              >
                Lou et al. 2023
              </a>
              , P3). All counts below are zero until then.
            </div>
          </div>
          {onLoadDemo && (
            <button
              onClick={onLoadDemo}
              disabled={demoLoading}
              className="px-4 py-2 text-[13px] rounded-sm shrink-0"
              style={{
                background: demoLoading ? "var(--border-strong)" : "#00a3a6",
                color: "#fff",
                fontWeight: 700,
                letterSpacing: "0.02em",
                fontFamily: '"Raleway", sans-serif',
                cursor: demoLoading ? "not-allowed" : "pointer",
                border: "none",
              }}
            >
              {demoLoading ? "Loading…" : "Load demo data"}
            </button>
          )}
        </div>
      )}

      {runMetadata && <RunMetadataBlock meta={runMetadata} />}

      <div className="grid md:grid-cols-3 lg:grid-cols-6 gap-3 mt-8 mb-4">
        <Stat label="Events" value={counts.total} />
        <Stat label="Samples involved" value={counts.samples} />
        <Stat label="Mean rate" value={`${(counts.avgRate * 100).toFixed(2)}%`} />
        <Stat
          label="Mean introduced %"
          value={
            avgIntroducedPct == null
              ? "—"
              : `${avgIntroducedPct.toFixed(1)}%`
          }
        />
        <Stat label="Validated (TP)" value={counts.tp} tone="good" />
        <Stat label="Rejected (FP)" value={counts.fp} tone="bad" />
      </div>

      {(events.length > 0 || metadata || plateMap || cascadeCount > 0) && (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 xl:grid-cols-7 gap-3 mb-10">
          {actionEnabled && (
            <Stat
              label="To keep"
              value={keepCount}
              tone={keepCount > 0 ? "good" : "neutral"}
            />
          )}
          {actionEnabled && (
            <Stat
              label="To suppress"
              value={suppressCount}
              tone={suppressCount > 0 ? "bad" : "neutral"}
            />
          )}
          {events.length > 0 && (
            <Stat
              label="Connected components"
              value={componentCount}
            />
          )}
          {metadata && (
            <Stat
              label="Annotated samples (metadata)"
              value={`${annotatedCount}`}
            />
          )}
          {metadata && (
            <Stat
              label="Related samples (same subject)"
              value={relatedCount}
              tone={relatedCount > 0 ? "warn" : "neutral"}
            />
          )}
          {plateMap && (
            <Stat
              label="Adjacent wells on plate"
              value={adjacentCount}
              tone={adjacentCount > 0 ? "good" : "neutral"}
            />
          )}
          {cascadeCount > 0 && (
            <Stat label="Cascades detected" value={cascadeCount} tone="bad" />
          )}
        </div>
      )}

      {!hasAb && (
        <div
          className="flex items-start gap-3 p-4 mb-8 rounded-sm"
          style={{ background: "var(--bg-alert)", border: "1px solid #ed6e6c", color: "#8a2422" }}
        >
          <AlertCircle className="w-5 h-5 shrink-0 mt-0.5" />
          <div className="text-[13px] leading-relaxed">
            <strong>No abundance table loaded.</strong> You can still sort events by
            probability and rate, but scatterplots and the 5-criteria diagnostic checks
            require <code>species_abundance.tsv</code>.
          </div>
        </div>
      )}

      {/* One column per metric (rate / probability / introduced), with
          Top above Bottom — visually pairs each Top with its Bottom. */}
      <div
        className={`grid gap-x-8 gap-y-6 ${
          eventsWithIntroduced.length > 0
            ? "md:grid-cols-2 lg:grid-cols-3"
            : "md:grid-cols-2"
        }`}
      >
        <div className="space-y-6">
          <TopList
            title="Top 5 by contamination rate"
            items={topByRate}
            onOpen={onOpen}
            fmt={(e) => `${(e.rate * 100).toFixed(2)}%`}
          />
          <TopList
            title="Bottom 5 by contamination rate"
            items={bottomByRate}
            onOpen={onOpen}
            fmt={(e) => `${(e.rate * 100).toFixed(2)}%`}
          />
        </div>
        <div className="space-y-6">
          <TopList
            title="Top 5 by probability"
            items={topByScore}
            onOpen={onOpen}
            fmt={(e) => e.score.toFixed(3)}
          />
          <TopList
            title="Bottom 5 by probability"
            items={bottomByScore}
            onOpen={onOpen}
            fmt={(e) => e.score.toFixed(3)}
          />
        </div>
        {eventsWithIntroduced.length > 0 && (
          <div className="space-y-6">
            <TopList
              title="Top 5 by introduced %"
              items={topByIntroduced}
              onOpen={onOpen}
              fmt={(e) => formatIntroducedPct(e.introducedPct)}
            />
            <TopList
              title="Bottom 5 by introduced %"
              items={bottomByIntroduced}
              onOpen={onOpen}
              fmt={(e) => formatIntroducedPct(e.introducedPct)}
            />
          </div>
        )}
      </div>
    </div>
  );
};

