const FilterDivider = () => (
  <div
    className="self-stretch w-px mx-0.5"
    style={{ background: FILTER_DIVIDER_BG }}
  />
);

const VERDICT_SEGMENTS = [
  { id: "true_positive", color: "#00a3a6", label: "true positive" },
  { id: "false_positive", color: "#ed6e6c", label: "false positive" },
  { id: "uncertain", color: "var(--border-strong)", label: "uncertain" },
  { id: "pending", color: "var(--border)", label: "pending" },
];

const VerdictDistribution = ({ events }) => {
  const counts = useMemo(() => {
    const c = { true_positive: 0, false_positive: 0, uncertain: 0, pending: 0 };
    for (const e of events) {
      const v = e.verdict;
      if (v === "true_positive" || v === "false_positive" || v === "uncertain") c[v] += 1;
      else c.pending += 1;
    }
    return c;
  }, [events]);
  const total = events.length;
  if (total === 0) return null;
  const tip = VERDICT_SEGMENTS
    .map((s) => `${s.label}: ${counts[s.id]}`)
    .join(" · ");
  return (
    <div
      className="flex h-2 rounded-full overflow-hidden"
      style={{ width: 64, background: "var(--border)" }}
      title={tip}
    >
      {VERDICT_SEGMENTS.map((s) => {
        const w = (counts[s.id] / total) * 100;
        if (w === 0) return null;
        return (
          <div
            key={s.id}
            style={{ width: `${w}%`, background: s.color }}
          />
        );
      })}
    </div>
  );
};

const SliderChip = ({ label, value, cutoffBadge, children, title }) => (
  <FilterChip title={title}>
    <span style={FILTER_LABEL_STYLE}>{label}</span>
    {children}
    <span className="tabular text-[12px]" style={FILTER_VALUE_STYLE}>
      {value}
    </span>
    {cutoffBadge}
  </FilterChip>
);

const EventFilterBar = ({
  filter,
  setFilter,
  metadata,
  plateMap,
  runMetadata,
  onBulkApply,
  hasAb,
  events,
  actionEnabled,
  children,
}) => {
  const cutoff = parseFloat(runMetadata?.probability_cutoff);
  const hasCutoff = Number.isFinite(cutoff) && cutoff > 0;
  const rc = parseFloat(runMetadata?.rate_cutoff);
  const hasRateCutoff = Number.isFinite(rc) && rc > 0;

  // Floor the probability slider at whichever is lower: the crocodeel
  // probability_cutoff (events below were never written), or the actual
  // minimum score among the loaded events (the user may have added a
  // manual event with a lower score via Explore pairs). Falls back to 0
  // when neither signal is available.
  const datasetScoreMin = useMemo(() => {
    if (!Array.isArray(events) || events.length === 0) return null;
    let m = Infinity;
    for (const e of events) {
      const s = e?.score;
      if (typeof s === "number" && s < m) m = s;
    }
    return Number.isFinite(m) ? m : null;
  }, [events]);
  const scoreMin = useMemo(() => {
    const candidates = [];
    if (hasCutoff) candidates.push(cutoff);
    if (datasetScoreMin != null) candidates.push(datasetScoreMin);
    if (candidates.length === 0) return 0;
    return Math.max(0, Math.floor(Math.min(...candidates) * 100) / 100);
  }, [hasCutoff, cutoff, datasetScoreMin]);
  const effectiveMinScore = Math.max(filter.minScore || 0, scoreMin);

  const showSubject = !!metadata;
  const showGroup = !!metadata?.hasGroupIdCol;
  const showWells = !!plateMap;
  const hasContextFilters = showSubject || showGroup || showWells;
  const activeContextCount =
    (showSubject && filter.subject && filter.subject !== "any" ? 1 : 0) +
    (showGroup && filter.group && filter.group !== "any" ? 1 : 0) +
    (showWells && filter.adjacent && filter.adjacent !== "any" ? 1 : 0);

  const [popoverOpen, setPopoverOpen] = useState(false);
  const popoverRef = useRef(null);
  useEffect(() => {
    if (!popoverOpen) return;
    const handle = (e) => {
      if (popoverRef.current && !popoverRef.current.contains(e.target)) {
        setPopoverOpen(false);
      }
    };
    document.addEventListener("mousedown", handle);
    return () => document.removeEventListener("mousedown", handle);
  }, [popoverOpen]);

  const [verdictPopoverOpen, setVerdictPopoverOpen] = useState(false);
  const verdictPopoverRef = useRef(null);
  const [actionPopoverOpen, setActionPopoverOpen] = useState(false);
  const actionPopoverRef = useRef(null);
  useEffect(() => {
    if (!actionPopoverOpen) return;
    const handle = (e) => {
      if (
        actionPopoverRef.current &&
        !actionPopoverRef.current.contains(e.target)
      ) {
        setActionPopoverOpen(false);
      }
    };
    document.addEventListener("mousedown", handle);
    return () => document.removeEventListener("mousedown", handle);
  }, [actionPopoverOpen]);
  useEffect(() => {
    if (!verdictPopoverOpen) return;
    const handle = (e) => {
      if (
        verdictPopoverRef.current &&
        !verdictPopoverRef.current.contains(e.target)
      ) {
        setVerdictPopoverOpen(false);
      }
    };
    document.addEventListener("mousedown", handle);
    return () => document.removeEventListener("mousedown", handle);
  }, [verdictPopoverOpen]);

  const VERDICT_OPTIONS = [
    { id: "pending", label: "pending" },
    { id: "true_positive", label: "true positive" },
    { id: "false_positive", label: "false positive" },
    { id: "uncertain", label: "uncertain" },
  ];
  const selectedVerdicts = Array.isArray(filter.verdicts)
    ? filter.verdicts
    : VERDICT_OPTIONS.map((v) => v.id);
  const allVerdictsSelected = selectedVerdicts.length === VERDICT_OPTIONS.length;
  const verdictLabel = allVerdictsSelected
    ? "verdicts"
    : selectedVerdicts.length === 0
      ? "no verdicts"
      : selectedVerdicts.length === 1
        ? VERDICT_OPTIONS.find((v) => v.id === selectedVerdicts[0])?.label ||
          "verdicts"
        : `${selectedVerdicts.length} verdicts`;
  const toggleVerdict = (id) => {
    const next = selectedVerdicts.includes(id)
      ? selectedVerdicts.filter((v) => v !== id)
      : [...selectedVerdicts, id];
    setFilter({ ...filter, verdicts: next });
  };

  const cutoffBadge = (text, tip) => (
    <span
      className="text-[10px] px-1.5 py-0.5 rounded-sm"
      title={tip}
      style={FILTER_CUTOFF_STYLE}
    >
      {text}
    </span>
  );

  const selectStyle = {
    background: FILTER_CHIP_BG,
    border: FILTER_CHIP_BORDER,
    color: "var(--ink)",
    fontWeight: 500,
  };

  return (
    <div
      className="flex flex-wrap gap-2 mb-4 items-center p-2 rounded-md"
      style={{ background: FILTER_PANEL_BG, border: FILTER_PANEL_BORDER }}
    >
      {/* Search */}
      <div className="relative">
        <Search
          className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5"
          style={{ color: "var(--ink-muted)" }}
        />
        <input
          value={filter.q}
          onChange={(e) => setFilter({ ...filter, q: e.target.value })}
          placeholder="sample…"
          className="pl-7 pr-3 py-1 text-[12px] rounded-md w-44 outline-none"
          style={selectStyle}
        />
      </div>

      <FilterDivider />

      {/* Thresholds */}
      <SliderChip
        label="rate"
        value={formatRatePct(filter.minRate)}
        cutoffBadge={
          hasRateCutoff &&
          cutoffBadge(
            `≥ ${rc}`,
            `CroCoDeEL was run with rate_cutoff = ${rc} — events below were never written to the file`,
          )
        }
        title="Contamination rate: estimated proportion of the contaminated sample that originates from the source. Slider is log-scaled from 0.01% to 100%."
      >
        <input
          type="range"
          min={RATE_LOG_MIN}
          max={RATE_LOG_MAX}
          step={0.05}
          value={rateToSlider(filter.minRate)}
          onChange={(e) =>
            setFilter({
              ...filter,
              minRate: sliderToRate(parseFloat(e.target.value)),
            })
          }
          style={{ accentColor: "#00a3a6", width: 72 }}
          title="Log-scaled (0.01% to 100%)"
        />
      </SliderChip>

      <SliderChip
        label="probability"
        value={effectiveMinScore.toFixed(2)}
        title="CroCoDeEL Random-Forest probability that the contamination event is real (0–1). Higher = more confident. Slider starts at the dataset's lowest score (events below the run cutoff were never written)."
        cutoffBadge={
          hasCutoff &&
          cutoffBadge(
            `≥ ${cutoff}`,
            `CroCoDeEL was run with probability_cutoff = ${cutoff} — events below were never written to the file`,
          )
        }
      >
        <input
          type="range"
          min={scoreMin}
          max={1}
          step={0.01}
          value={effectiveMinScore}
          onChange={(e) =>
            setFilter({ ...filter, minScore: parseFloat(e.target.value) })
          }
          style={{ accentColor: "#00a3a6", width: 72 }}
        />
      </SliderChip>

      {hasAb && (
        <SliderChip
          label="introduced"
          value={`${(filter.minIntroduced || 0).toFixed(1)}%`}
          title="Percentage of the target sample's species that are likely introduced by the contamination event (vs. native to the target). Higher = more of the target's biodiversity is explained by the source."
        >
          <input
            type="range"
            min={0}
            max={100}
            step={0.5}
            value={filter.minIntroduced || 0}
            onChange={(e) =>
              setFilter({
                ...filter,
                minIntroduced: parseFloat(e.target.value),
              })
            }
            style={{ accentColor: "#00a3a6", width: 72 }}
            title="% of target species introduced by the contamination"
          />
        </SliderChip>
      )}

      <FilterDivider />

      {/* Verdict + context popover */}
      <div className="relative" ref={verdictPopoverRef}>
        <button
          type="button"
          onClick={() => setVerdictPopoverOpen((o) => !o)}
          className="flex items-center justify-center rounded-md outline-none relative"
          style={{
            width: 28,
            height: 28,
            background: !allVerdictsSelected
              ? "rgba(0,163,166,0.10)"
              : FILTER_CHIP_BG,
            border: !allVerdictsSelected
              ? "1px solid #00a3a6"
              : FILTER_CHIP_BORDER,
            color: "var(--ink)",
          }}
          title={`Verdicts: ${verdictLabel}`}
          aria-label={`Verdicts: ${verdictLabel}`}
        >
          <Scale className="w-4 h-4" />
          {!allVerdictsSelected && (
            <span
              className="absolute text-[9px] rounded-full"
              style={{
                top: -4,
                right: -4,
                background: "#00a3a6",
                color: "#fff",
                fontWeight: 700,
                fontFamily: '"Raleway", sans-serif',
                lineHeight: "13px",
                minWidth: 13,
                height: 13,
                padding: "0 3px",
                textAlign: "center",
              }}
            >
              {selectedVerdicts.length}
            </span>
          )}
        </button>
        {verdictPopoverOpen && (
          <div
            className="absolute right-0 top-full mt-1.5 z-20 p-3 rounded-md flex flex-col gap-2"
            style={{
              background: "var(--bg-card)",
              border: "1px solid var(--border-strong)",
              boxShadow: "0 8px 24px rgba(39,86,98,0.12)",
              minWidth: 180,
            }}
          >
            <div
              className="text-[10px] tracking-[0.1em] uppercase mb-1"
              style={{
                color: "var(--ink-muted)",
                fontWeight: 700,
                fontFamily: '"Raleway", sans-serif',
              }}
            >
              Verdicts
            </div>
            {VERDICT_OPTIONS.map((v) => (
              <label
                key={v.id}
                className="flex items-center gap-2 text-[12px] cursor-pointer"
                style={{ color: "var(--ink)", userSelect: "none" }}
              >
                <input
                  type="checkbox"
                  checked={selectedVerdicts.includes(v.id)}
                  onChange={() => toggleVerdict(v.id)}
                  style={{ accentColor: "#00a3a6" }}
                />
                {v.label}
              </label>
            ))}
            <div className="flex items-center gap-3 mt-1">
              <button
                type="button"
                onClick={() =>
                  setFilter({
                    ...filter,
                    verdicts: VERDICT_OPTIONS.map((v) => v.id),
                  })
                }
                className="text-[11px]"
                style={{
                  color: "#00a3a6",
                  fontWeight: 600,
                  fontFamily: '"Raleway", sans-serif',
                }}
              >
                all
              </button>
              <button
                type="button"
                onClick={() => setFilter({ ...filter, verdicts: [] })}
                className="text-[11px]"
                style={{
                  color: "var(--ink-muted)",
                  fontWeight: 600,
                  fontFamily: '"Raleway", sans-serif',
                }}
              >
                none
              </button>
            </div>
          </div>
        )}
      </div>

      {actionEnabled && (
        <div className="relative" ref={actionPopoverRef}>
          <button
            type="button"
            onClick={() => setActionPopoverOpen((o) => !o)}
            className="flex items-center justify-center rounded-md outline-none relative"
            style={{
              width: 28,
              height: 28,
              background: filter.action ? "rgba(0,163,166,0.10)" : FILTER_CHIP_BG,
              border: filter.action ? "1px solid #00a3a6" : FILTER_CHIP_BORDER,
              color: "var(--ink)",
            }}
            title={
              filter.action
                ? `Action: only ${filter.action}`
                : "Filter by action (suppress / keep)"
            }
            aria-label="Filter by action"
          >
            <Save className="w-4 h-4" />
            {filter.action && (
              <span
                className="absolute text-[9px] rounded-full"
                style={{
                  top: -4,
                  right: -4,
                  background: "#00a3a6",
                  color: "#fff",
                  fontWeight: 700,
                  fontFamily: '"Raleway", sans-serif',
                  lineHeight: "13px",
                  minWidth: 13,
                  height: 13,
                  padding: "0 3px",
                  textAlign: "center",
                }}
              >
                1
              </span>
            )}
          </button>
          {actionPopoverOpen && (
            <div
              className="absolute right-0 top-full mt-1.5 z-20 p-3 rounded-md flex flex-col gap-2"
              style={{
                background: "var(--bg-card)",
                border: "1px solid var(--border-strong)",
                boxShadow: "0 8px 24px rgba(39,86,98,0.12)",
                minWidth: 160,
              }}
            >
              <div
                className="text-[10px] tracking-[0.1em] uppercase mb-1"
                style={{
                  color: "var(--ink-muted)",
                  fontWeight: 700,
                  fontFamily: '"Raleway", sans-serif',
                }}
              >
                Action
              </div>
              {[
                { id: null, label: "Any" },
                { id: "keep", label: "Keep only", Icon: Save },
                { id: "suppress", label: "Suppress only", Icon: Trash2 },
              ].map((opt) => (
                <label
                  key={String(opt.id)}
                  className="flex items-center gap-2 text-[12px] cursor-pointer"
                  style={{ color: "var(--ink)", userSelect: "none" }}
                >
                  <input
                    type="radio"
                    name="filter-action"
                    checked={(filter.action || null) === opt.id}
                    onChange={() => setFilter({ ...filter, action: opt.id })}
                    style={{ accentColor: "#00a3a6" }}
                  />
                  {opt.Icon && <opt.Icon className="w-3.5 h-3.5" />}
                  {opt.label}
                </label>
              ))}
            </div>
          )}
        </div>
      )}

      {hasContextFilters && (
        <div className="relative" ref={popoverRef}>
          <button
            type="button"
            onClick={() => setPopoverOpen((o) => !o)}
            className="flex items-center justify-center rounded-md outline-none relative"
            style={{
              width: 28,
              height: 28,
              background:
                activeContextCount > 0 ? "rgba(0,163,166,0.10)" : FILTER_CHIP_BG,
              border:
                activeContextCount > 0
                  ? "1px solid #00a3a6"
                  : FILTER_CHIP_BORDER,
              color: "var(--ink)",
            }}
            title={
              activeContextCount > 0
                ? `Context filters (${activeContextCount} active)`
                : "Context filters"
            }
            aria-label="Context filters"
          >
            <Layers className="w-4 h-4" />
            {activeContextCount > 0 && (
              <span
                className="absolute text-[9px] rounded-full"
                style={{
                  top: -4,
                  right: -4,
                  background: "#00a3a6",
                  color: "#fff",
                  fontWeight: 700,
                  fontFamily: '"Raleway", sans-serif',
                  lineHeight: "13px",
                  minWidth: 13,
                  height: 13,
                  padding: "0 3px",
                  textAlign: "center",
                }}
              >
                {activeContextCount}
              </span>
            )}
          </button>
          {popoverOpen && (
            <div
              className="absolute right-0 top-full mt-1.5 z-20 p-3 rounded-md flex flex-col gap-2.5"
              style={{
                background: "var(--bg-card)",
                border: "1px solid var(--border-strong)",
                boxShadow: "0 8px 24px rgba(39,86,98,0.12)",
                minWidth: 220,
              }}
            >
              <div
                className="text-[10px] tracking-[0.1em] uppercase"
                style={{
                  color: "var(--ink-muted)",
                  fontWeight: 700,
                  fontFamily: '"Raleway", sans-serif',
                }}
              >
                Context filters
              </div>
              {showSubject && (
                <label className="flex flex-col gap-1 text-[12px]">
                  <span style={FILTER_LABEL_STYLE}>subject</span>
                  <select
                    value={filter.subject || "any"}
                    onChange={(e) =>
                      setFilter({ ...filter, subject: e.target.value })
                    }
                    className="px-2 py-1 text-[12px] rounded-md outline-none"
                    style={selectStyle}
                  >
                    <option value="any">any</option>
                    <option value="same">same subject</option>
                    <option value="different">different subject</option>
                  </select>
                </label>
              )}
              {showGroup && (
                <label className="flex flex-col gap-1 text-[12px]">
                  <span style={FILTER_LABEL_STYLE}>group</span>
                  <select
                    value={filter.group || "any"}
                    onChange={(e) =>
                      setFilter({ ...filter, group: e.target.value })
                    }
                    className="px-2 py-1 text-[12px] rounded-md outline-none"
                    style={selectStyle}
                  >
                    <option value="any">any</option>
                    <option value="same">same group</option>
                    <option value="different">different group</option>
                  </select>
                </label>
              )}
              {showWells && (
                <label className="flex flex-col gap-1 text-[12px]">
                  <span style={FILTER_LABEL_STYLE}>wells</span>
                  <select
                    value={filter.adjacent || "any"}
                    onChange={(e) =>
                      setFilter({ ...filter, adjacent: e.target.value })
                    }
                    className="px-2 py-1 text-[12px] rounded-md outline-none"
                    style={selectStyle}
                  >
                    <option value="any">any</option>
                    <option value="adjacent">adjacent only</option>
                    <option value="non-adjacent">non-adjacent only</option>
                  </select>
                </label>
              )}
              {activeContextCount > 0 && (
                <button
                  type="button"
                  onClick={() =>
                    setFilter({
                      ...filter,
                      subject: "any",
                      group: "any",
                      adjacent: "any",
                    })
                  }
                  className="self-start text-[11px] mt-1"
                  style={{
                    color: "#00a3a6",
                    fontWeight: 600,
                    fontFamily: '"Raleway", sans-serif',
                  }}
                >
                  clear filters
                </button>
              )}
            </div>
          )}
        </div>
      )}

      {onBulkApply && (
        <button
          type="button"
          onClick={onBulkApply}
          className="flex items-center justify-center rounded-md outline-none"
          style={{
            width: 28,
            height: 28,
            // Bulk apply is the primary action on this bar — deep teal
            // matches the brand and reads as authoritative without
            // shouting at the user like the violet did.
            background: "rgba(39,86,98,0.10)",
            border: "1px solid #275662",
            color: "#275662",
          }}
          title="Bulk apply a verdict to all events matching probability / rate / criteria filters"
          aria-label="Bulk apply verdict"
        >
          <ListChecks className="w-4 h-4" />
        </button>
      )}

      {children}
    </div>
  );
};

/* ---------- EVENTS TABLE ---------- */
const EventsTable = ({
  events,
  total,
  filter,
  setFilter,
  sort,
  setSort,
  onPick,
  setVerdict,
  metadata,
  plateMap,
  runMetadata,
  onBulkApply,
  hasAb,
  actionEnabled,
  setAction,
  pageSize,
}) => {
  const PAGE_SIZE = pageSize || 500;
  const [page, setPage] = useState(1);
  // Reset to page 1 when filter or sort changes. Don't include `events` —
  // the parent re-derives that array on every verdict toggle, which would
  // jump the user back to page 1 each time they curate.
  useEffect(() => {
    setPage(1);
  }, [filter.q, filter.minScore, filter.minRate, filter.minIntroduced, filter.verdicts, filter.subject, filter.group, filter.adjacent, sort.by, sort.dir, total]);
  const totalPages = Math.max(1, Math.ceil(events.length / PAGE_SIZE));
  const safePage = Math.min(Math.max(1, page), totalPages);
  const startIdx = (safePage - 1) * PAGE_SIZE;
  const visible = events.slice(startIdx, startIdx + PAGE_SIZE);

  const toggleSort = (by) =>
    setSort({
      by,
      dir: sort.by === by && sort.dir === "desc" ? "asc" : "desc",
    });
  const SortIcon = ({ col }) =>
    sort.by !== col ? null : sort.dir === "desc" ? (
      <ChevronDown className="inline w-3 h-3" />
    ) : (
      <ChevronUp className="inline w-3 h-3" />
    );
  const hasContext = metadata || plateMap;

  return (
    <div>
      <SectionTitle eyebrow="Events" title="Curate each flag">
        Filter, sort, and click a row to open the event in the validation workflow.
      </SectionTitle>

      <EventFilterBar
        filter={filter}
        setFilter={setFilter}
        metadata={metadata}
        plateMap={plateMap}
        runMetadata={runMetadata}
        onBulkApply={onBulkApply}
        hasAb={hasAb}
        events={events}
        actionEnabled={actionEnabled}
      >
        <div className="ml-auto flex items-center gap-2.5">
          <VerdictDistribution events={events} />
          <span className="text-[12px]" style={{ color: "var(--ink-muted)" }}>
            {events.length === 0
              ? `0 / ${total}`
              : totalPages > 1
                ? `${startIdx + 1}–${startIdx + visible.length} of ${events.length} (filtered) / ${total} total`
                : `${events.length} / ${total}`}
          </span>
        </div>
      </EventFilterBar>

      <div
        className="rounded-sm overflow-x-auto"
        style={{ border: "1px solid var(--border)" }}
      >
        <table className="w-full text-[13px]">
          <thead>
            <tr style={{ background: "var(--bg-soft)", borderBottom: "2px solid #00a3a6" }}>
              <Th
                onClick={() => toggleSort("source")}
                title="Source sample — the contaminant. Click to sort alphabetically."
              >
                Source <SortIcon col="source" />
              </Th>
              <Th title="Direction: source contaminates target.">→</Th>
              <Th
                onClick={() => toggleSort("target")}
                title="Target sample — the one that received the contamination. Click to sort alphabetically."
              >
                Target <SortIcon col="target" />
              </Th>
              <Th
                onClick={() => toggleSort("rate")}
                right
                title="Estimated proportion of the target sample that originates from the source. Click to sort numerically."
              >
                Rate <SortIcon col="rate" />
              </Th>
              <Th
                onClick={() => toggleSort("score")}
                right
                title="CroCoDeEL Random-Forest probability that this contamination event is real (0–1). Higher = more confident. Click to sort."
              >
                Probability <SortIcon col="score" />
              </Th>
              <Th
                onClick={() => toggleSort("introducedPct")}
                right
                title="Percentage of the target sample's species likely introduced by this contamination event. Click to sort."
              >
                Introduced <SortIcon col="introducedPct" />
              </Th>
              <Th
                onClick={() => toggleSort("speciesCount")}
                right
                title="Number of species CroCoDeEL identified as introduced by this contamination event. Click to sort."
              >
                Species <SortIcon col="speciesCount" />
              </Th>
              {hasContext && (
                <Th title="Sample context derived from metadata + plate map: relatedness, plate proximity, cascade flag.">
                  Context
                </Th>
              )}
              <Th
                onClick={() => toggleSort("verdict")}
                title="Your curation decision — TP (true positive), FP (false positive), Uncertain or Pending. Click to sort by verdict."
              >
                Verdict <SortIcon col="verdict" />
              </Th>
              {actionEnabled && (
                <Th
                  onClick={() => toggleSort("action")}
                  title="Suppress / keep — what to do with this sample in downstream analyses. Click to sort."
                >
                  Action <SortIcon col="action" />
                </Th>
              )}
            </tr>
          </thead>
          <tbody>
            {visible.map((e) => {
              const related = areRelated(metadata, e.source, e.target);
              const pd = plateDistance(plateMap, e.source, e.target);
              return (
                <tr
                  key={e.id}
                  style={{ borderBottom: "1px solid var(--border-soft)" }}
                  onMouseOver={(ev) => (ev.currentTarget.style.background = "var(--bg-soft)")}
                  onMouseOut={(ev) => (ev.currentTarget.style.background = "")}
                >
                  <td
                    className="px-3 py-2.5 cursor-pointer"
                    onClick={() => onPick(e.id)}
                    style={{ fontWeight: 600, color: "var(--ink)" }}
                  >
                    {e.source}
                    {metadata && (
                      <div className="mt-1">
                        <SampleFlags
                          flags={flagSample(e.source, metadata)}
                          compact
                        />
                      </div>
                    )}
                  </td>
                  <td className="px-1" style={{ color: "#00a3a6" }}>→</td>
                  <td
                    className="px-3 py-2.5 cursor-pointer"
                    onClick={() => onPick(e.id)}
                    style={{ fontWeight: 600, color: "var(--ink)" }}
                  >
                    {e.target}
                    {metadata && (
                      <div className="mt-1">
                        <SampleFlags
                          flags={flagSample(e.target, metadata)}
                          compact
                        />
                      </div>
                    )}
                  </td>
                  <td className="px-3 py-2.5 tabular text-right">
                    <RateBar v={e.rate} />
                  </td>
                  <td className="px-3 py-2.5 tabular text-right">
                    <ScoreBar v={e.score} />
                  </td>
                  <td className="px-3 py-2.5 tabular text-right">
                    <IntroducedBar v={e.introducedPct} />
                  </td>
                  <td
                    className="px-3 py-2.5 text-right tabular"
                    style={{ color: "var(--ink-muted)" }}
                  >
                    {e.introduced.length}
                  </td>
                  {hasContext && (
                    <td className="px-3 py-2.5">
                      <div className="flex gap-1 flex-wrap">
                        {related?.related === true && (
                          <Pill tone="warn">
                            {related.kind === "group" ? "same group" : "related"}
                          </Pill>
                        )}
                        {pd && pd.samePlate && pd.distance != null && pd.distance <= 1 && (
                          <Pill tone="bad">adjacent</Pill>
                        )}
                        {pd && pd.samePlate && pd.distance === 2 && (
                          <Pill tone="warn">Δ=2</Pill>
                        )}
                        {pd && pd.samePlate === false && (
                          <Pill tone="neutral">different plates</Pill>
                        )}
                        {e.cascade && <Pill tone="violet">cascade</Pill>}
                      </div>
                    </td>
                  )}
                  <td className="px-3 py-2.5">
                    <div className="flex gap-1">
                      <QuickBtn
                        active={e.verdict === "true_positive"}
                        onClick={() =>
                          setVerdict(
                            e.id,
                            e.verdict === "true_positive" ? "pending" : "true_positive",
                          )
                        }
                        tone="good"
                        title="mark as true positive"
                      >
                        <CheckCircle2 className="w-3.5 h-3.5" />
                      </QuickBtn>
                      <QuickBtn
                        active={e.verdict === "false_positive"}
                        onClick={() =>
                          setVerdict(
                            e.id,
                            e.verdict === "false_positive" ? "pending" : "false_positive",
                          )
                        }
                        tone="bad"
                        title="mark as false positive"
                      >
                        <XCircle className="w-3.5 h-3.5" />
                      </QuickBtn>
                      <QuickBtn
                        active={e.verdict === "uncertain"}
                        onClick={() =>
                          setVerdict(
                            e.id,
                            e.verdict === "uncertain" ? "pending" : "uncertain",
                          )
                        }
                        tone="warn"
                        title="mark as uncertain"
                      >
                        <HelpCircle className="w-3.5 h-3.5" />
                      </QuickBtn>
                    </div>
                  </td>
                  {actionEnabled && (
                    <td className="px-3 py-2.5">
                      {e.verdict === "true_positive" ||
                      e.verdict === "false_positive" ? (
                        <div className="flex gap-1">
                          {[
                            {
                              id: "keep",
                              Icon: Save,
                              color: "#00a3a6",
                              title: "Keep this sample (acknowledged contamination, but small enough to retain)",
                            },
                            {
                              id: "suppress",
                              Icon: Trash2,
                              color: "#ed6e6c",
                              title: "Suppress this contaminated sample from downstream analyses",
                            },
                          ].map((opt) => {
                            const defaultAction =
                              e.verdict === "false_positive" ? "keep" : "suppress";
                            const active = (e.action || defaultAction) === opt.id;
                            const Icon = opt.Icon;
                            return (
                              <button
                                key={opt.id}
                                type="button"
                                onClick={(ev) => {
                                  ev.stopPropagation();
                                  setAction(e.id, opt.id);
                                }}
                                title={opt.title}
                                aria-label={opt.title}
                                className="rounded-sm flex items-center justify-center"
                                style={{
                                  width: 26,
                                  height: 26,
                                  background: active ? opt.color : "var(--bg-card)",
                                  color: active ? "#fff" : "var(--ink-muted)",
                                  border: active
                                    ? "1px solid transparent"
                                    : "1px solid var(--border)",
                                  cursor: "pointer",
                                }}
                              >
                                <Icon className="w-3.5 h-3.5" />
                              </button>
                            );
                          })}
                        </div>
                      ) : (
                        <span className="text-[11px]" style={{ color: "var(--border-strong)" }}>
                          —
                        </span>
                      )}
                    </td>
                  )}
                </tr>
              );
            })}
            {events.length === 0 && (
              <tr>
                <td
                  colSpan={8 + (hasContext ? 1 : 0) + (actionEnabled ? 1 : 0)}
                  className="px-3 py-8 text-center text-[13px]"
                  style={{ color: "var(--ink-muted)" }}
                >
                  No events match these filters.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {totalPages > 1 && (
        <Pagination
          page={safePage}
          totalPages={totalPages}
          onChange={setPage}
        />
      )}
    </div>
  );
};

/* ---------- SCATTER TAB ---------- */
/* ----- Mini scatter thumbnail (for the gallery) ----- */
// Fixed log10(relative-abundance) range used across every gallery thumbnail
// so the eye can compare contamination patterns across cards. Anything
// below 1e-8 is clamped to the floor, anything above 1 is impossible
// (relative abundances sum to 1).
const MINI_LO = -8;
const MINI_HI = 0;

const MiniScatter = ({ scatter, width = 220, height = 180 }) => {
  if (!scatter) return null;
  // Wider left + bottom padding to fit corner tick labels.
  const pad = { l: 18, r: 6, t: 6, b: 14 };
  const w = width - pad.l - pad.r;
  const h = height - pad.t - pad.b;
  if (scatter.error) {
    return (
      <div
        style={{
          width: "100%",
          aspectRatio: `${width} / ${height}`,
          background: "var(--bg-alert)",
          border: "1px solid #ed6e6c",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          color: "#8a2422",
          fontSize: 10,
          textAlign: "center",
          padding: 8,
          lineHeight: 1.3,
        }}
      >
        sample name not found in abundance table
      </div>
    );
  }
  // Use the per-dataset log10 range when buildScatter has provided one
  // (parseAbundance computes it from the actual matrix). Fall back to
  // the global -8..0 default for safety.
  const lo = scatter.logRange?.min ?? MINI_LO;
  const hi = scatter.logRange?.max ?? MINI_HI;
  const floor = Math.pow(10, lo);
  const pts = scatter.points.map((p) => ({
    ...p,
    lx: Math.log10(Math.max(p.x, floor)),
    ly: Math.log10(Math.max(p.y, floor)),
  }));
  if (pts.length === 0) {
    return (
      <div
        style={{
          width,
          height,
          background: "var(--bg-softer)",
          border: "1px solid var(--border)",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          color: "var(--ink-muted)",
          fontSize: 11,
        }}
      >
        no data
      </div>
    );
  }
  const sx = (v) => pad.l + ((v - lo) / (hi - lo)) * w;
  const sy = (v) => pad.t + h - ((v - lo) / (hi - lo)) * h;
  return (
    <svg
      viewBox={`0 0 ${width} ${height}`}
      preserveAspectRatio="xMidYMid meet"
      style={{ display: "block", background: "var(--bg-card)", width: "100%", height: "auto" }}
    >
      {/* axes */}
      <line
        x1={pad.l}
        y1={pad.t + h}
        x2={pad.l + w}
        y2={pad.t + h}
        stroke="var(--border-strong)"
        strokeWidth="0.75"
      />
      <line
        x1={pad.l}
        y1={pad.t}
        x2={pad.l}
        y2={pad.t + h}
        stroke="var(--border-strong)"
        strokeWidth="0.75"
      />
      {/* axis ticks — every integer log10 step. Label step adapts to
          the dataset range: every 1 if the span is small, every 2
          otherwise, to avoid crowding the thumbnail. */}
      {(() => {
        const ticks = [];
        const labelStep = hi - lo <= 4 ? 1 : 2;
        for (let v = lo; v <= hi; v++) {
          const labeled = (v - hi) % labelStep === 0;
          // Y-axis (left edge): horizontal tick mark + optional label
          ticks.push(
            <line
              key={`yt-${v}`}
              x1={pad.l - (labeled ? 3 : 2)}
              y1={sy(v)}
              x2={pad.l}
              y2={sy(v)}
              stroke="var(--border-strong)"
              strokeWidth="0.75"
            />,
          );
          if (labeled) {
            ticks.push(
              <text
                key={`yl-${v}`}
                x={pad.l - 4}
                y={sy(v) + 3}
                textAnchor="end"
                fontSize="8"
                fill="#797870"
                fontFamily="system-ui, sans-serif"
              >
                {v}
              </text>,
            );
          }
          // X-axis (bottom edge): vertical tick mark + optional label
          ticks.push(
            <line
              key={`xt-${v}`}
              x1={sx(v)}
              y1={pad.t + h}
              x2={sx(v)}
              y2={pad.t + h + (labeled ? 3 : 2)}
              stroke="var(--border-strong)"
              strokeWidth="0.75"
            />,
          );
          if (labeled) {
            ticks.push(
              <text
                key={`xl-${v}`}
                x={sx(v)}
                y={pad.t + h + 11}
                textAnchor="middle"
                fontSize="8"
                fill="#797870"
                fontFamily="system-ui, sans-serif"
              >
                {v}
              </text>,
            );
          }
        }
        return ticks;
      })()}
      {/* contamination line */}
      {scatter.logC != null && (
        <line
          x1={sx(lo)}
          y1={sy(lo - scatter.logC)}
          x2={sx(hi)}
          y2={sy(hi - scatter.logC)}
          stroke="#ed6e6c"
          strokeWidth="1"
          strokeDasharray="3 2"
        />
      )}
      {/* points */}
      {pts.map((p, i) => (
        <circle
          key={i}
          cx={sx(p.lx)}
          cy={sy(p.ly)}
          r={p.onLine ? 2 : 1.4}
          fill={p.onLine ? "#ed6e6c" : "#7d8b91"}
          fillOpacity={p.onLine ? 0.9 : 0.55}
        />
      ))}
      {/* y=x identity (drawn last so it stays on top) */}
      <line
        x1={sx(lo)}
        y1={sy(lo)}
        x2={sx(hi)}
        y2={sy(hi)}
        stroke="#7d8b91"
        strokeWidth="0.7"
        strokeDasharray="1.5 2.5"
        strokeOpacity="0.85"
      />
    </svg>
  );
};

/* ----- Gallery card ----- */
const GalleryCard = ({
  event,
  ab,
  metadata,
  plateMap,
  onPick,
  setVerdict,
  actionEnabled,
  setAction,
}) => {
  const scatter = useMemo(() => buildScatter(ab, event), [ab, event]);
  const related = areRelated(metadata, event.source, event.target);
  const pd = plateDistance(plateMap, event.source, event.target);
  const verdictDot =
    event.verdict === "true_positive" ? "#00a3a6" :
    event.verdict === "false_positive" ? "#ed6e6c" :
    event.verdict === "uncertain" ? "var(--border-strong)" : null;
  // Action popover — opens only when the user clicks TP/FP. Lets the
  // curator override the default action (TP→suppress, FP→keep) without
  // leaving the gallery. Auto-closes 2 s after the mouse leaves the
  // popover; immediately on outside click.
  const [actionPopover, setActionPopover] = useState(null); // null | "true_positive" | "false_positive"
  const closeTimerRef = useRef(null);
  const popoverRef = useRef(null);
  useEffect(() => {
    if (!actionPopover) return;
    const handle = (ev) => {
      if (popoverRef.current && !popoverRef.current.contains(ev.target)) {
        setActionPopover(null);
      }
    };
    document.addEventListener("mousedown", handle);
    return () => document.removeEventListener("mousedown", handle);
  }, [actionPopover]);
  const cancelCloseTimer = () => {
    if (closeTimerRef.current) {
      window.clearTimeout(closeTimerRef.current);
      closeTimerRef.current = null;
    }
  };
  const startCloseTimer = () => {
    cancelCloseTimer();
    closeTimerRef.current = window.setTimeout(() => {
      setActionPopover(null);
    }, 2000);
  };
  const toggleVerdict = (target) => (e) => {
    e.stopPropagation();
    if (!setVerdict) return;
    cancelCloseTimer();
    const next = event.verdict === target ? "pending" : target;
    setVerdict(event.id, next);
    if (
      actionEnabled &&
      (next === "true_positive" || next === "false_positive")
    ) {
      setActionPopover(next);
    } else {
      setActionPopover(null);
    }
  };

  return (
    <div
      role="button"
      tabIndex={0}
      onClick={() => onPick(event.id)}
      onKeyDown={(e) => {
        if (e.key === "Enter" || e.key === " ") {
          e.preventDefault();
          onPick(event.id);
        }
      }}
      className="text-left rounded-sm cursor-pointer"
      style={{
        border: "1px solid var(--border)",
        background: "var(--bg-card)",
        transition: "transform 0.12s, box-shadow 0.12s, border-color 0.12s",
        padding: 0,
        // Allow the action popover to overflow on the right of the card.
        // Lift this card above its grid siblings while the popover is
        // open so the popover doesn't get hidden under neighbouring
        // cards (each card creates its own stacking context via the
        // hover `transform`).
        overflow: "visible",
        width: "100%",
        position: "relative",
        zIndex: actionPopover ? 30 : "auto",
      }}
      onMouseEnter={(e) => {
        e.currentTarget.style.transform = "translateY(-2px)";
        e.currentTarget.style.boxShadow = "0 6px 14px -6px rgba(39, 86, 98, 0.25)";
        e.currentTarget.style.borderColor = "#00a3a6";
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.transform = "";
        e.currentTarget.style.boxShadow = "";
        e.currentTarget.style.borderColor = "var(--border)";
      }}
    >
      <div
        style={{
          background: "var(--bg-card)",
          borderBottom: "1px solid var(--border-soft)",
          position: "relative",
        }}
      >
        <MiniScatter scatter={scatter} width={240} height={180} />
        {setVerdict && (
          <div
            className="absolute right-1.5 top-1/2 -translate-y-1/2 flex flex-col gap-1"
            onClick={(e) => e.stopPropagation()}
          >
            {[
              {
                id: "true_positive",
                tone: "good",
                label: "mark as true positive",
                Icon: CheckCircle2,
              },
              {
                id: "false_positive",
                tone: "bad",
                label: "mark as false positive",
                Icon: XCircle,
              },
              {
                id: "uncertain",
                tone: "neutral",
                label: "mark as uncertain",
                Icon: HelpCircle,
              },
            ].map(({ id, tone, label, Icon }) => {
              const active = event.verdict === id;
              const bg = active
                ? tone === "good"
                  ? "#00a3a6"
                  : tone === "bad"
                    ? "#ed6e6c"
                    : "var(--border-strong)"
                : "rgba(255,255,255,0.85)";
              const color = active ? "var(--bg-card)" : "#275662";
              return (
                <button
                  key={id}
                  type="button"
                  onClick={toggleVerdict(id)}
                  onMouseEnter={() => {
                    // Re-show the popover on hover only if this event
                    // already has an action committed for the current
                    // verdict — gives the curator a quick way to flip
                    // their previous choice without re-clicking the
                    // verdict button. Fresh / pending events stay quiet.
                    if (
                      actionEnabled &&
                      event.action &&
                      event.verdict === id &&
                      (id === "true_positive" || id === "false_positive")
                    ) {
                      cancelCloseTimer();
                      setActionPopover(id);
                    }
                  }}
                  onMouseLeave={() => {
                    if (actionPopover) startCloseTimer();
                  }}
                  title={label}
                  className="rounded-full"
                  style={{
                    width: 28,
                    height: 28,
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    background: bg,
                    color,
                    border: active
                      ? "1px solid transparent"
                      : "1px solid #c4c0b3",
                    backdropFilter: active ? "none" : "blur(4px)",
                    transition: "background 0.12s, color 0.12s",
                  }}
                >
                  <Icon className="w-4 h-4" />
                </button>
              );
            })}
          </div>
        )}
        {actionEnabled && actionPopover && (
          <div
            ref={popoverRef}
            onClick={(e) => e.stopPropagation()}
            onMouseEnter={cancelCloseTimer}
            onMouseLeave={startCloseTimer}
            className="absolute z-20 flex flex-col gap-1 p-1.5 rounded-md"
            style={{
              // Anchor just to the right of the verdict-button column,
              // outside the card. z-20 floats it above neighbouring
              // gallery cards.
              right: -44,
              top: "50%",
              transform: "translateY(-50%)",
              background: "var(--bg-card)",
              border: "1px solid var(--border-strong)",
              boxShadow: "0 8px 24px rgba(39,86,98,0.18)",
            }}
          >
            <div
              className="text-[9px] tracking-[0.1em] uppercase text-center mb-0.5"
              style={{
                color: "var(--ink-muted)",
                fontWeight: 700,
                fontFamily: '"Raleway", sans-serif',
              }}
            >
              Action
            </div>
            {[
              {
                id: "keep",
                Icon: Save,
                color: "#00a3a6",
                title: "Keep this sample",
              },
              {
                id: "suppress",
                Icon: Trash2,
                color: "#ed6e6c",
                title: "Suppress this sample",
              },
            ].map((opt) => {
              const defaultAction =
                actionPopover === "false_positive" ? "keep" : "suppress";
              const active = (event.action || defaultAction) === opt.id;
              const Icon = opt.Icon;
              return (
                <button
                  key={opt.id}
                  type="button"
                  onClick={(ev) => {
                    ev.stopPropagation();
                    setAction(event.id, opt.id);
                    setActionPopover(null);
                  }}
                  title={opt.title}
                  aria-label={opt.title}
                  className="rounded-full flex items-center justify-center"
                  style={{
                    width: 28,
                    height: 28,
                    background: active ? opt.color : "var(--bg-card)",
                    color: active ? "#fff" : "var(--ink-muted)",
                    border: active
                      ? "1px solid transparent"
                      : "1px solid var(--border-strong)",
                    cursor: "pointer",
                  }}
                >
                  <Icon className="w-3.5 h-3.5" />
                </button>
              );
            })}
          </div>
        )}
      </div>
      <div style={{ padding: "8px 10px" }}>
        <div className="flex items-center gap-1.5 mb-1.5">
          {verdictDot && (
            <span
              className="w-2 h-2 rounded-full shrink-0"
              style={{ background: verdictDot }}
            />
          )}
          <div
            className="text-[11px] truncate"
            style={{
              color: "var(--ink)",
              fontWeight: 700,
              fontFamily: '"Raleway", sans-serif',
            }}
            title={`${event.source} → ${event.target}`}
          >
            {event.source} → {event.target}
          </div>
        </div>
        <div
          className="grid gap-x-2 gap-y-0.5 text-[10px] tabular mb-1.5"
          style={{
            color: "var(--ink-muted)",
            gridTemplateColumns: "max-content 1fr",
          }}
        >
          <span
            style={{
              fontFamily: '"Raleway", sans-serif',
              letterSpacing: "0.04em",
              textTransform: "uppercase",
              fontSize: 9,
              fontWeight: 700,
            }}
          >
            probability
          </span>
          <b style={{ color: "var(--ink)", textAlign: "right" }}>
            {event.score.toFixed(3)}
          </b>
          <span
            style={{
              fontFamily: '"Raleway", sans-serif',
              letterSpacing: "0.04em",
              textTransform: "uppercase",
              fontSize: 9,
              fontWeight: 700,
            }}
          >
            rate
          </span>
          <b style={{ color: "var(--ink)", textAlign: "right" }}>
            {(event.rate * 100).toFixed(2)}%
          </b>
          {event.introducedPct != null && (
            <>
              <span
                style={{
                  fontFamily: '"Raleway", sans-serif',
                  letterSpacing: "0.04em",
                  textTransform: "uppercase",
                  fontSize: 9,
                  fontWeight: 700,
                }}
              >
                introduced
              </span>
              <b style={{ color: "var(--ink)", textAlign: "right" }}>
                {formatIntroducedPct(event.introducedPct)}
              </b>
            </>
          )}
        </div>
        {(related?.related === true ||
          (pd && pd.samePlate && pd.distance != null && pd.distance <= 2) ||
          event.cascade) && (
          <div className="flex flex-wrap gap-1">
            {related?.related === true && (
              <Pill tone="warn">
                {related.kind === "group" ? "same group" : "related"}
              </Pill>
            )}
            {pd && pd.samePlate && pd.distance != null && pd.distance <= 1 && (
              <Pill tone="bad">adjacent</Pill>
            )}
            {pd && pd.samePlate && pd.distance === 2 && (
              <Pill tone="warn">Δ=2</Pill>
            )}
            {event.cascade && <Pill tone="violet">cascade</Pill>}
          </div>
        )}
      </div>
    </div>
  );
};

/* ----- Scatterplot gallery tab ----- */
/* ============================================================================
   SampleCombobox — searchable dropdown for picking a sample, with optional
   contextual groups (e.g. "Plate neighbors of source", "Same subject"). The
   dropdown opens on focus, filters by case-insensitive substring as the user
   types, and groups samples into named sections. Clicking an item, or
   pressing Enter/Tab, selects it.
   ============================================================================ */
const SampleCombobox = ({
  value,
  onChange,
  samples,
  groups = null,
  placeholder = "Type to search…",
  invalid = false,
}) => {
  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState(value || "");
  const [highlightIdx, setHighlightIdx] = useState(0);
  const containerRef = useRef(null);
  const inputRef = useRef(null);

  // Keep the displayed text in sync with the value prop
  useEffect(() => {
    setQuery(value || "");
  }, [value]);

  // Close on outside click
  useEffect(() => {
    if (!open) return;
    const onDown = (ev) => {
      if (
        containerRef.current &&
        !containerRef.current.contains(ev.target)
      ) {
        setOpen(false);
      }
    };
    window.addEventListener("mousedown", onDown);
    return () => window.removeEventListener("mousedown", onDown);
  }, [open]);

  // Build the filtered+grouped list. If `groups` is provided, we honour
  // them; otherwise we fall back to a single anonymous group with all
  // samples. Filtering is case-insensitive substring match.
  const filteredGroups = useMemo(() => {
    const q = query.trim().toLowerCase();
    const filterList = (lst) =>
      q === "" ? lst : lst.filter((s) => s.toLowerCase().includes(q));
    if (groups && groups.length > 0) {
      // Track samples already shown in earlier groups so they don't
      // appear twice.
      const seen = new Set();
      const out = [];
      groups.forEach((g) => {
        const filtered = filterList(g.samples).filter((s) => {
          if (seen.has(s)) return false;
          seen.add(s);
          return true;
        });
        if (filtered.length > 0) {
          out.push({ label: g.label, accent: g.accent, samples: filtered });
        }
      });
      // Catch-all "Other samples" group with anything not yet seen
      const others = filterList(samples).filter((s) => !seen.has(s));
      if (others.length > 0) {
        out.push({ label: "Other samples", accent: "#797870", samples: others });
      }
      return out;
    }
    return [
      { label: null, accent: "#797870", samples: filterList(samples) },
    ];
  }, [query, samples, groups]);

  // Flat list of suggestions for keyboard navigation
  const flatList = useMemo(() => {
    const out = [];
    filteredGroups.forEach((g) =>
      g.samples.forEach((s) => out.push({ sample: s, group: g.label })),
    );
    return out;
  }, [filteredGroups]);

  const totalMatches = flatList.length;

  const selectSample = (s) => {
    onChange(s);
    setQuery(s);
    setOpen(false);
    setHighlightIdx(0);
  };

  const handleKeyDown = (e) => {
    if (e.key === "ArrowDown") {
      e.preventDefault();
      setOpen(true);
      setHighlightIdx((i) => Math.min(totalMatches - 1, i + 1));
    } else if (e.key === "ArrowUp") {
      e.preventDefault();
      setHighlightIdx((i) => Math.max(0, i - 1));
    } else if (e.key === "Enter") {
      if (open && flatList[highlightIdx]) {
        e.preventDefault();
        selectSample(flatList[highlightIdx].sample);
      }
    } else if (e.key === "Escape") {
      setOpen(false);
    } else if (e.key === "Tab") {
      // Don't intercept tab — the user might want to leave the field.
      // But if the dropdown is open, take the highlighted item.
      if (open && flatList[highlightIdx]) {
        selectSample(flatList[highlightIdx].sample);
      }
    }
  };

  return (
    <div ref={containerRef} style={{ position: "relative" }}>
      <input
        ref={inputRef}
        type="text"
        value={query}
        onChange={(e) => {
          setQuery(e.target.value);
          onChange(e.target.value); // mirror to parent so validation runs live
          setOpen(true);
          setHighlightIdx(0);
        }}
        onFocus={() => setOpen(true)}
        onKeyDown={handleKeyDown}
        placeholder={placeholder}
        className="w-full px-3 py-2 text-[12px] rounded-sm"
        style={{
          border: `1px solid ${invalid ? "#ed6e6c" : "var(--border)"}`,
          background: "var(--bg-card)",
          color: "var(--ink)",
          fontFamily: "ui-monospace, monospace",
        }}
      />
      {open && totalMatches > 0 && (
        <div
          style={{
            position: "absolute",
            top: "calc(100% + 2px)",
            left: 0,
            right: 0,
            background: "var(--bg-card)",
            border: "1px solid var(--border)",
            borderRadius: 3,
            maxHeight: 280,
            overflowY: "auto",
            zIndex: 30,
            boxShadow: "0 4px 12px rgba(39,86,98,0.12)",
          }}
        >
          {filteredGroups.map((g, gi) => {
            // Compute the global index offset for keyboard highlight
            const offset = filteredGroups
              .slice(0, gi)
              .reduce((s, gg) => s + gg.samples.length, 0);
            return (
              <div key={gi}>
                {g.label && (
                  <div
                    className="text-[9px] tracking-[0.1em] uppercase px-3 py-1"
                    style={{
                      color: g.accent,
                      fontWeight: 700,
                      fontFamily: '"Raleway", sans-serif',
                      background: "var(--bg-soft)",
                      borderTop: gi > 0 ? "1px solid #e6e8e8" : "none",
                    }}
                  >
                    {g.label} ({g.samples.length})
                  </div>
                )}
                {g.samples.map((s, si) => {
                  const flatIdx = offset + si;
                  const isHi = flatIdx === highlightIdx;
                  return (
                    <div
                      key={s}
                      onMouseDown={(e) => {
                        e.preventDefault();
                        selectSample(s);
                      }}
                      onMouseEnter={() => setHighlightIdx(flatIdx)}
                      style={{
                        padding: "6px 12px",
                        fontSize: 12,
                        fontFamily: "ui-monospace, monospace",
                        color: "var(--ink)",
                        background: isHi ? "var(--bg-info)" : "transparent",
                        cursor: "pointer",
                      }}
                    >
                      {s}
                    </div>
                  );
                })}
              </div>
            );
          })}
        </div>
      )}
      {open && totalMatches === 0 && (
        <div
          style={{
            position: "absolute",
            top: "calc(100% + 2px)",
            left: 0,
            right: 0,
            background: "var(--bg-card)",
            border: "1px solid var(--border)",
            borderRadius: 3,
            padding: "8px 12px",
            fontSize: 11,
            color: "var(--ink-muted)",
            zIndex: 30,
            boxShadow: "0 4px 12px rgba(39,86,98,0.12)",
          }}
        >
          No matching samples
        </div>
      )}
    </div>
  );
};


/* ============================================================================
   Pair exploration — let the user pick any two samples and look at
   their scatterplot, then optionally add the pair as a manually-curated TP
   event. Useful for catching false negatives that CroCoDeEL didn't flag.
   ============================================================================ */
const ExplorePairs = ({
  ab,
  samples,
  onAddManualEvent,
  existingPairs,
  plateMap,
  metadata,
  actionEnabled,
}) => {
  const [src, setSrc] = useState("");
  const [tgt, setTgt] = useState("");
  // Sliders work in log-space for rate (so the user gets fine control at
  // low rates without a 50× larger range up high). Range: log10(rate)
  // from -3 (0.1%) to log10(0.5) ≈ -0.301 (50%). Default at -2 (1%).
  const [rateLog, setRateLog] = useState(-2);
  const [probability, setProbability] = useState(0.9);
  const [verdict, setVerdict] = useState("true_positive");
  // Action override for the manual event when actionEnabled. Mirrors
  // setVerdict's defaults: TP → suppress, FP → keep.
  const [action, setAction] = useState("suppress");
  const [notes, setNotes] = useState("Manually added by user");
  const [feedback, setFeedback] = useState(null);

  // Reset action to the verdict's default whenever the verdict changes.
  useEffect(() => {
    if (verdict === "true_positive") setAction("suppress");
    else if (verdict === "false_positive") setAction("keep");
    else setAction(null);
  }, [verdict]);

  const rate = Math.pow(10, rateLog);

  // Build a fake "event" object so we can reuse buildScatter / Scatterplot.
  const fakeEvent = useMemo(() => {
    if (!src || !tgt || src === tgt) return null;
    return {
      id: "preview",
      source: src,
      target: tgt,
      rate,
      score: probability,
      introduced: [], // populated below from the user's rate
      verdict: "pending",
      notes: "",
    };
  }, [src, tgt, rate, probability]);

  // Compute the "introduced" list — species within 0.3 decade of the
  // user-placed contamination line. This matches CroCoDeEL's tolerance and
  // means the manually-added event will go through the same diagnostic
  // checks as auto-flagged ones.
  const introducedFromLine = useMemo(() => {
    if (!ab || !fakeEvent) return [];
    const sc = buildScatter(ab, { ...fakeEvent, introduced: [] });
    if (!sc || sc.error || sc.logC == null) return [];
    return sc.points
      .filter((p) => {
        if (p.x <= 0 || p.y <= 0) return false;
        const expectedY = Math.log10(p.x) - sc.logC;
        return Math.abs(Math.log10(p.y) - expectedY) < 0.3;
      })
      .map((p) => p.species);
  }, [ab, fakeEvent]);

  const eventForPlot = useMemo(() => {
    if (!fakeEvent) return null;
    return { ...fakeEvent, introduced: introducedFromLine };
  }, [fakeEvent, introducedFromLine]);

  const scatter = useMemo(
    () => (eventForPlot && eventForPlot.source !== eventForPlot.target ? buildScatter(ab, eventForPlot) : null),
    [ab, eventForPlot],
  );

  const pairAlreadyExists = useMemo(() => {
    if (!src || !tgt) return false;
    return existingPairs.has(`${src}\u0000${tgt}`);
  }, [src, tgt, existingPairs]);

  // Contextual groups for the SOURCE combobox. Source has no parent
  // context (the user picks it first), so we just expose the full
  // sample list with no priority groups. We could surface "samples
  // appearing in flagged events" but that would bias the user away
  // from FN audit, which is the whole point.
  const srcGroups = null;

  // Contextual groups for the TARGET combobox, computed from the
  // currently-selected source. When a source is picked, we promote
  // (a) plate neighbors (Δ ≤ 1 well) and (b) same-subject samples to
  // the top of the dropdown — these are the most likely places where
  // CroCoDeEL might have missed a contamination. The categories also
  // help the user learn the dataset's structure as they browse.
  const tgtGroups = useMemo(() => {
    if (!src) return null;
    const groups = [];
    if (plateMap) {
      const neighbors = samples.filter((s) => {
        if (s === src) return false;
        const d = plateDistance(plateMap, src, s);
        return d != null && d <= 1;
      });
      if (neighbors.length > 0) {
        groups.push({
          label: "Plate neighbors of source",
          accent: "#ed6e6c",
          samples: neighbors,
        });
      }
    }
    if (metadata) {
      const related = samples.filter((s) => {
        if (s === src) return false;
        const r = areRelated(metadata, src, s);
        return r && r.related;
      });
      if (related.length > 0) {
        groups.push({
          label: "Same subject as source",
          accent: "#00a3a6",
          samples: related,
        });
      }
    }
    return groups.length > 0 ? groups : null;
  }, [src, samples, plateMap, metadata]);

  const canSave =
    src && tgt && src !== tgt && !pairAlreadyExists;

  const handleSave = () => {
    if (!canSave) return;
    onAddManualEvent({
      source: src,
      target: tgt,
      rate,
      score: probability,
      introduced: introducedFromLine,
      verdict,
      notes,
      action: actionEnabled ? action : undefined,
    });
    const verdictLabel =
      verdict === "true_positive"
        ? "true positive"
        : verdict === "false_positive"
          ? "false positive"
          : "uncertain";
    setFeedback({
      kind: "success",
      message: `Added ${src} → ${tgt} as a ${verdictLabel} event.`,
    });
    setTimeout(() => setFeedback(null), 4000);
    // Reset the form so the user can immediately add another
    setSrc("");
    setTgt("");
    setRateLog(-2);
    setProbability(0.9);
    setVerdict("true_positive");
    setNotes("Manually added by user");
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-[minmax(0,1fr)_minmax(0,520px)] gap-5 items-start">
      <div
        className="rounded-sm p-4"
        style={{
          background: "var(--bg-soft)",
          border: "1px solid var(--border)",
        }}
      >
        <div
          className="text-[10px] tracking-[0.15em] uppercase mb-2"
          style={{
            color: "#ed6e6c",
            fontWeight: 700,
            fontFamily: '"Raleway", sans-serif',
          }}
        >
          Explore new pairs
        </div>
        <p className="text-[12px] mb-3" style={{ color: "var(--ink-soft)", lineHeight: 1.55 }}>
          Pick two samples to inspect their scatterplot, even if CroCoDeEL didn't
          flag them. Useful for catching missed contamination events (false
          negatives), e.g. when two samples sit next to each other on the plate
          or share a metadata feature. If you spot a real contamination, set the
          rate and probability you estimate, then save it as a true positive
          event. The pair will be tagged with the note "Manually added by user"
          and included in your exports.
        </p>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-3 mb-3">
          <div>
            <label
              className="text-[10px] tracking-[0.1em] uppercase block mb-1"
              style={{
                color: "var(--ink-muted)",
                fontWeight: 700,
                fontFamily: '"Raleway", sans-serif',
              }}
            >
              Source sample
            </label>
            <SampleCombobox
              value={src}
              onChange={setSrc}
              samples={samples}
              groups={srcGroups}
              placeholder="Type to search… e.g. ERS848718"
              invalid={src !== "" && !samples.includes(src)}
            />
          </div>
          <div>
            <label
              className="text-[10px] tracking-[0.1em] uppercase block mb-1"
              style={{
                color: "var(--ink-muted)",
                fontWeight: 700,
                fontFamily: '"Raleway", sans-serif',
              }}
            >
              Target sample (contaminated)
            </label>
            <SampleCombobox
              value={tgt}
              onChange={setTgt}
              samples={samples}
              groups={tgtGroups}
              placeholder={
                src
                  ? "Pick from neighbors / same subject / others…"
                  : "Pick a source first"
              }
              invalid={tgt !== "" && !samples.includes(tgt)}
            />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-3">
          <div>
            <label
              className="text-[10px] tracking-[0.1em] uppercase block mb-1"
              style={{
                color: "var(--ink-muted)",
                fontWeight: 700,
                fontFamily: '"Raleway", sans-serif',
              }}
            >
              Estimated contamination rate ·{" "}
              <span style={{ color: "var(--ink)" }}>
                {(rate * 100).toFixed(2)}%
              </span>
            </label>
            <input
              type="range"
              min="-3"
              max="-0.0044"
              step="0.05"
              value={rateLog}
              onChange={(e) => setRateLog(parseFloat(e.target.value))}
              style={{ width: "100%", accentColor: "#ed6e6c" }}
            />
            <div
              className="flex justify-between text-[10px] mt-0.5"
              style={{ color: "var(--ink-muted)" }}
            >
              <span>0.1%</span>
              <span>1%</span>
              <span>10%</span>
              <span>99%</span>
            </div>
            <div className="text-[10px] mt-1" style={{ color: "var(--ink-muted)" }}>
              Drags the contamination line to log10(rate). Slider is
              log-scaled.
            </div>
          </div>
          <div>
            <label
              className="text-[10px] tracking-[0.1em] uppercase block mb-1"
              style={{
                color: "var(--ink-muted)",
                fontWeight: 700,
                fontFamily: '"Raleway", sans-serif',
              }}
            >
              Your estimated probability (confidence) ·{" "}
              <span style={{ color: "var(--ink)" }}>
                {probability.toFixed(2)}
              </span>
            </label>
            <input
              type="range"
              min="0"
              max="1"
              step="0.05"
              value={probability}
              onChange={(e) => setProbability(parseFloat(e.target.value))}
              style={{ width: "100%", accentColor: "#00a3a6" }}
            />
            <div
              className="flex justify-between text-[10px] mt-0.5"
              style={{ color: "var(--ink-muted)" }}
            >
              <span>0.0</span>
              <span>0.5</span>
              <span>1.0</span>
            </div>
            <div className="text-[10px] mt-1" style={{ color: "var(--ink-muted)" }}>
              Like CroCoDeEL's RF probability — your subjective confidence
              that this is a real contamination.
            </div>
          </div>
        </div>

        {/* Verdict picker (TP / FP / Uncertain) */}
        <div className="mb-3">
          <label
            className="text-[10px] tracking-[0.1em] uppercase block mb-2"
            style={{
              color: "var(--ink-muted)",
              fontWeight: 700,
              fontFamily: '"Raleway", sans-serif',
            }}
          >
            Verdict
          </label>
          <div className="flex gap-2 flex-wrap">
            {[
              { id: "true_positive", label: "True positive", color: "#00a3a6" },
              { id: "false_positive", label: "False positive", color: "#ed6e6c" },
              { id: "uncertain", label: "Uncertain", color: "var(--border-strong)" },
            ].map((v) => {
              const active = verdict === v.id;
              return (
                <button
                  key={v.id}
                  onClick={() => setVerdict(v.id)}
                  className="px-3 py-1.5 text-[11px] rounded-sm flex items-center gap-1.5"
                  style={{
                    background: active ? v.color : "var(--bg-card)",
                    color: active ? "#fff" : "var(--ink)",
                    border: `1px solid ${active ? v.color : "var(--border)"}`,
                    fontWeight: 700,
                    fontFamily: '"Raleway", sans-serif',
                    cursor: "pointer",
                  }}
                >
                  {active && <CheckCircle2 className="w-3 h-3" />}
                  {v.label}
                </button>
              );
            })}
          </div>
        </div>

        {/* Action picker — only when the suppress/keep feature is on
            and the verdict is TP or FP. */}
        {actionEnabled &&
          (verdict === "true_positive" || verdict === "false_positive") && (
            <div className="mb-3">
              <label
                className="text-[10px] tracking-[0.1em] uppercase block mb-2"
                style={{
                  color: "var(--ink-muted)",
                  fontWeight: 700,
                  fontFamily: '"Raleway", sans-serif',
                }}
              >
                Action
              </label>
              <div className="flex gap-2 flex-wrap">
                {[
                  {
                    id: "keep",
                    Icon: Save,
                    label: "Keep",
                    color: "#00a3a6",
                    title: "Keep this sample (acknowledged contamination, but small enough to retain).",
                  },
                  {
                    id: "suppress",
                    Icon: Trash2,
                    label: "Suppress",
                    color: "#ed6e6c",
                    title: "Drop this contaminated sample from downstream analyses.",
                  },
                ].map((opt) => {
                  const active = action === opt.id;
                  const Icon = opt.Icon;
                  return (
                    <button
                      key={opt.id}
                      type="button"
                      onClick={() => setAction(opt.id)}
                      title={opt.title}
                      className="px-3 py-1.5 text-[11px] rounded-sm flex items-center gap-1.5"
                      style={{
                        background: active ? opt.color : "var(--bg-card)",
                        color: active ? "#fff" : "var(--ink)",
                        border: `1px solid ${active ? opt.color : "var(--border)"}`,
                        fontWeight: 700,
                        fontFamily: '"Raleway", sans-serif',
                        cursor: "pointer",
                      }}
                    >
                      <Icon className="w-3 h-3" />
                      {opt.label}
                    </button>
                  );
                })}
              </div>
            </div>
          )}

        {/* Notes field — pre-filled but editable */}
        <div className="mb-3">
          <label
            className="text-[10px] tracking-[0.1em] uppercase block mb-1"
            style={{
              color: "var(--ink-muted)",
              fontWeight: 700,
              fontFamily: '"Raleway", sans-serif',
            }}
          >
            Comment
          </label>
          <textarea
            value={notes}
            onChange={(e) => setNotes(e.target.value)}
            rows={2}
            className="w-full px-3 py-2 text-[12px] rounded-sm"
            style={{
              border: "1px solid var(--border)",
              background: "var(--bg-card)",
              color: "var(--ink)",
              fontFamily:
                '"Avenir Next", "Nunito Sans", system-ui, sans-serif',
              resize: "vertical",
            }}
          />
        </div>

        <div className="flex items-center gap-3 flex-wrap">
          <button
            onClick={handleSave}
            disabled={!canSave}
            className="px-4 py-2 text-[12px] rounded-sm flex items-center gap-2"
            style={{
              background: canSave ? "#00a3a6" : "var(--border)",
              color: canSave ? "#fff" : "#797870",
              border: "none",
              fontWeight: 700,
              letterSpacing: "0.02em",
              fontFamily: '"Raleway", sans-serif',
              cursor: canSave ? "pointer" : "not-allowed",
            }}
          >
            <CheckCircle2 className="w-4 h-4" />
            Save as new contamination event
          </button>
          {!src || !tgt ? (
            <span className="text-[11px]" style={{ color: "var(--ink-muted)" }}>
              Pick both source and target to see the plot.
            </span>
          ) : src === tgt ? (
            <span className="text-[11px]" style={{ color: "#ed6e6c" }}>
              Source and target must differ.
            </span>
          ) : pairAlreadyExists ? (
            <span className="text-[11px]" style={{ color: "#ed6e6c" }}>
              This pair is already in your events list.
            </span>
          ) : (
            <span className="text-[11px]" style={{ color: "var(--ink-muted)" }}>
              {introducedFromLine.length} species fall on the line you placed
              {(() => {
                if (!ab || !tgt) return null;
                let n = 0;
                for (const sp of ab.species) {
                  if ((ab.matrix[sp]?.[tgt] || 0) > 0) n++;
                }
                if (n === 0) return null;
                const pct = (introducedFromLine.length / n) * 100;
                return ` (${pct.toFixed(1)}% of ${tgt}'s species)`;
              })()}.
            </span>
          )}
          {feedback && (
            <span
              className="text-[11px] px-2 py-1 rounded-sm"
              style={{
                background: "#d8f0f1",
                color: "#00787a",
                fontWeight: 600,
              }}
            >
              ✓ {feedback.message}
            </span>
          )}
        </div>
      </div>

      <div
        className="rounded-sm p-4 flex flex-col gap-3"
        style={{
          background: "var(--bg-card)",
          border: "1px solid var(--border)",
        }}
      >
        <div
          className="text-[10px] tracking-[0.15em] uppercase"
          style={{
            color: "#ed6e6c",
            fontWeight: 700,
            fontFamily: '"Raleway", sans-serif',
          }}
        >
          Live preview
        </div>
        {scatter && !scatter.error ? (
          <div className="flex justify-center">
            <Scatterplot scatter={scatter} width={460} height={400} />
          </div>
        ) : scatter && scatter.error ? (
          <div
            className="p-4 rounded-sm text-[12px]"
            style={{
              background: "var(--bg-alert)",
              border: "1px solid #ed6e6c",
              color: "#8a2422",
            }}
          >
            {scatter.error}
          </div>
        ) : (
          <div
            className="p-8 rounded-sm text-center text-[12px]"
            style={{
              border: "1px dashed var(--border-strong)",
              color: "var(--ink-muted)",
            }}
          >
            Pick both source and target to see the scatterplot.
          </div>
        )}
        {/* Dynamic introduced-species summary — recomputed live as the
            user moves the rate / probability sliders. */}
        {(() => {
          const targetSpeciesCount = (() => {
            if (!ab || !tgt) return null;
            let n = 0;
            for (const sp of ab.species) {
              if ((ab.matrix[sp]?.[tgt] || 0) > 0) n++;
            }
            return n;
          })();
          const introducedCount = introducedFromLine.length;
          const pct =
            targetSpeciesCount && targetSpeciesCount > 0
              ? (introducedCount / targetSpeciesCount) * 100
              : null;
          return (
            <div
              className="grid grid-cols-2 gap-3"
              style={{ borderTop: "1px solid var(--border)", paddingTop: 12 }}
            >
              <div
                className="rounded-sm p-3"
                style={{
                  background: "var(--bg-soft)",
                  borderLeft: "4px solid #ed6e6c",
                }}
              >
                <div
                  className="text-[10px] tracking-[0.1em] uppercase"
                  style={{
                    color: "var(--ink-muted)",
                    fontWeight: 700,
                    fontFamily: '"Raleway", sans-serif',
                  }}
                >
                  Introduced species
                </div>
                <div
                  className="tabular mt-1"
                  style={{
                    fontWeight: 800,
                    fontSize: 24,
                    lineHeight: 1,
                    color: "var(--ink)",
                    fontFamily: '"Raleway", sans-serif',
                  }}
                >
                  {introducedCount}
                </div>
                <div
                  className="text-[11px] mt-1"
                  style={{ color: "var(--ink-muted)" }}
                >
                  on the line you placed
                </div>
              </div>
              <div
                className="rounded-sm p-3"
                style={{
                  background: "var(--bg-soft)",
                  borderLeft: `4px solid ${
                    pct == null
                      ? "var(--border-strong)"
                      : metricColor(pct, "introduced")
                  }`,
                }}
              >
                <div
                  className="text-[10px] tracking-[0.1em] uppercase"
                  style={{
                    color: "var(--ink-muted)",
                    fontWeight: 700,
                    fontFamily: '"Raleway", sans-serif',
                  }}
                >
                  % of {tgt || "target"} species
                </div>
                <div
                  className="tabular mt-1"
                  style={{
                    fontWeight: 800,
                    fontSize: 24,
                    lineHeight: 1,
                    color:
                      pct == null
                        ? "var(--ink-muted)"
                        : metricColor(pct, "introduced"),
                    fontFamily: '"Raleway", sans-serif',
                  }}
                >
                  {pct == null ? "—" : `${pct.toFixed(1)}%`}
                </div>
                <div
                  className="text-[11px] mt-1"
                  style={{ color: "var(--ink-muted)" }}
                >
                  {targetSpeciesCount != null
                    ? `${targetSpeciesCount} species observed in target`
                    : "load target to compute"}
                </div>
              </div>
            </div>
          );
        })()}
      </div>
    </div>
  );
};


/** Compact pagination control: First / Prev / page input / Next / Last.
    Renders nothing useful when totalPages <= 1 — caller decides whether to mount. */
const Pagination = ({ page, totalPages, onChange }) => {
  const [draft, setDraft] = useState(String(page));
  useEffect(() => {
    setDraft(String(page));
  }, [page]);

  const go = (p) => {
    const clamped = Math.min(Math.max(1, p), totalPages);
    onChange(clamped);
  };

  const btn = (label, target, disabled) => (
    <button
      onClick={() => go(target)}
      disabled={disabled}
      className="px-2.5 py-1 text-[11px] rounded-sm"
      style={{
        background: disabled ? "var(--border)" : "var(--bg-card)",
        color: disabled ? "#797870" : "#275662",
        border: "1px solid #275662",
        fontWeight: 600,
        fontFamily: '"Raleway", sans-serif',
        cursor: disabled ? "not-allowed" : "pointer",
        opacity: disabled ? 0.5 : 1,
      }}
    >
      {label}
    </button>
  );

  return (
    <div
      className="flex items-center gap-2 mt-6 flex-wrap"
      style={{ color: "var(--ink)" }}
    >
      {btn("« First", 1, page <= 1)}
      {btn("‹ Prev", page - 1, page <= 1)}
      <span
        className="text-[11px]"
        style={{ color: "var(--ink-muted)", fontFamily: '"Raleway", sans-serif' }}
      >
        Page
      </span>
      <input
        type="number"
        min={1}
        max={totalPages}
        value={draft}
        onChange={(e) => setDraft(e.target.value)}
        onBlur={() => {
          const n = parseInt(draft, 10);
          if (Number.isFinite(n)) go(n);
          else setDraft(String(page));
        }}
        onKeyDown={(e) => {
          if (e.key === "Enter") {
            e.currentTarget.blur();
          }
        }}
        className="px-2 py-1 text-[11px] rounded-sm w-16"
        style={{
          border: "1px solid #275662",
          color: "var(--ink)",
          background: "var(--bg-card)",
          fontFamily: '"Raleway", sans-serif',
        }}
      />
      <span
        className="text-[11px]"
        style={{ color: "var(--ink-muted)", fontFamily: '"Raleway", sans-serif' }}
      >
        of {totalPages}
      </span>
      {btn("Next ›", page + 1, page >= totalPages)}
      {btn("Last »", totalPages, page >= totalPages)}
    </div>
  );
};

const ScatterTab = ({
  events,
  filtered,
  filter,
  setFilter,
  ab,
  metadata,
  plateMap,
  runMetadata,
  setVerdict,
  onPick,
  onAddManualEvent,
  onBulkApply,
  actionEnabled,
  setAction,
  pageSize,
}) => {
  const [mode, setMode] = useState("flagged"); // "flagged" or "explore"
  const [sortBy, setSortBy] = useState("score");
  // Direction per sort key — defaults match what most users expect
  // (descending for numeric severity, ascending for alphabetical).
  const SORT_DEFAULT_DIR = { score: "desc", rate: "desc", introducedPct: "desc", source: "asc", pending: "asc", action: "asc" };
  const [sortDir, setSortDir] = useState(SORT_DEFAULT_DIR.score);
  const handleSortClick = (id) => {
    if (sortBy === id) {
      setSortDir((d) => (d === "desc" ? "asc" : "desc"));
    } else {
      setSortBy(id);
      setSortDir(SORT_DEFAULT_DIR[id] || "desc");
    }
  };
  const PAGE_SIZE = pageSize || 100;
  const [page, setPage] = useState(1);
  useEffect(() => {
    setPage(1);
  }, [sortBy, sortDir, filtered]);

  // Set of existing pairs (source\u0000target) to prevent duplicates when
  // adding manual events. Built once per events change.
  const existingPairs = useMemo(() => {
    const s = new Set();
    events.forEach((e) => s.add(`${e.source}\u0000${e.target}`));
    return s;
  }, [events]);

  if (!ab) {
    return (
      <div>
        <SectionTitle eyebrow="Scatterplots" title="Scatterplot gallery">
          Browse every flagged event as a scatterplot thumbnail. Click any card
          to open it in the Guided validation workflow.
        </SectionTitle>
        <div
          className="p-6 rounded-sm"
          style={{ background: "var(--bg-alert)", border: "1px solid #ed6e6c", color: "#8a2422" }}
        >
          <strong>Scatterplots require the abundance table.</strong> Drop{" "}
          <code>species_abundance.tsv</code> above to enable this view.
        </div>
      </div>
    );
  }

  const sorted = useMemo(() => {
    const copy = filtered.slice();
    const flip = sortDir === "asc" ? -1 : 1;
    if (sortBy === "score") copy.sort((a, b) => (b.score - a.score) * flip);
    else if (sortBy === "rate") copy.sort((a, b) => (b.rate - a.rate) * flip);
    else if (sortBy === "introducedPct") {
      // Treat null as -Infinity so events without an introduced% land at
      // the bottom of a descending sort (and top of ascending).
      copy.sort(
        (a, b) =>
          ((b.introducedPct ?? -Infinity) - (a.introducedPct ?? -Infinity)) *
          flip,
      );
    } else if (sortBy === "pending") {
      const rank = (v) =>
        v === "pending" ? 0 : v === "uncertain" ? 1 : v === "true_positive" ? 2 : 3;
      copy.sort(
        (a, b) =>
          (rank(a.verdict) - rank(b.verdict)) * flip ||
          (b.score - a.score) * flip,
      );
    } else if (sortBy === "source") {
      copy.sort((a, b) => a.source.localeCompare(b.source) * flip);
    } else if (sortBy === "action") {
      // Group by action — keep / suppress / none — and break ties by
      // descending probability so the most-confident calls bubble up
      // inside each action bucket.
      const rank = (v) => (v === "keep" ? 0 : v === "suppress" ? 1 : 2);
      copy.sort(
        (a, b) =>
          (rank(a.action) - rank(b.action)) * flip ||
          (b.score - a.score) * flip,
      );
    }
    return copy;
  }, [filtered, sortBy, sortDir]);

  const totalPages = Math.max(1, Math.ceil(sorted.length / PAGE_SIZE));
  const safePage = Math.min(Math.max(1, page), totalPages);
  const startIdx = (safePage - 1) * PAGE_SIZE;
  const visible = sorted.slice(startIdx, startIdx + PAGE_SIZE);

  return (
    <div>
      <SectionTitle eyebrow="Scatterplots" title="Scatterplot gallery">
        Browse every flagged event as a scatterplot thumbnail, or explore any
        two samples to look for missed contamination events (false negatives).
      </SectionTitle>

      {/* Mode toggle: flagged events vs free pair exploration */}
      <div
        className="inline-flex items-center rounded-sm mb-5"
        style={{ border: "1px solid #275662", padding: 2 }}
      >
        {[
          { id: "flagged", label: "Flagged events" },
          { id: "explore", label: "Explore new pairs" },
        ].map((m) => {
          const active = mode === m.id;
          return (
            <button
              key={m.id}
              onClick={() => setMode(m.id)}
              className="px-3 py-1.5 text-[11px] rounded-sm"
              style={{
                background: active ? "#275662" : "transparent",
                color: active ? "#fff" : "var(--ink)",
                fontWeight: 700,
                fontFamily: '"Raleway", sans-serif',
                border: "none",
                cursor: "pointer",
              }}
            >
              {m.label}
            </button>
          );
        })}
      </div>

      {mode === "explore" ? (
        <ExplorePairs
          ab={ab}
          samples={ab.samples}
          onAddManualEvent={onAddManualEvent}
          existingPairs={existingPairs}
          plateMap={plateMap}
          metadata={metadata}
          actionEnabled={actionEnabled}
        />
      ) : (
        <>
      <EventFilterBar
        filter={filter}
        setFilter={setFilter}
        metadata={metadata}
        plateMap={plateMap}
        runMetadata={runMetadata}
        onBulkApply={onBulkApply}
        hasAb={!!ab}
        events={events}
        actionEnabled={actionEnabled}
      >
        <div className="ml-auto flex items-center gap-2.5">
          <VerdictDistribution events={sorted} />
          <span className="text-[12px]" style={{ color: "var(--ink-muted)" }}>
            {sorted.length} / {events.length}
          </span>
        </div>
      </EventFilterBar>
      <div className="flex items-center gap-3 mb-6 flex-wrap">
        <span
          className="text-[11px] uppercase tracking-[0.1em]"
          style={{
            color: "var(--ink-muted)",
            fontWeight: 700,
            fontFamily: '"Raleway", sans-serif',
          }}
        >
          Sort by
        </span>
        {[
          { id: "score", label: "probability" },
          { id: "rate", label: "rate" },
          { id: "introducedPct", label: "introduced" },
          { id: "pending", label: "verdict" },
          ...(actionEnabled ? [{ id: "action", label: "action" }] : []),
          { id: "source", label: "source" },
        ].map((opt) => {
          const active = sortBy === opt.id;
          return (
            <button
              key={opt.id}
              onClick={() => handleSortClick(opt.id)}
              title={
                active
                  ? `Click to switch to ${sortDir === "desc" ? "ascending" : "descending"} order`
                  : `Sort by ${opt.label}`
              }
              className="px-3 py-1 text-[11px] rounded-sm"
              style={{
                background: active ? "#275662" : "var(--bg-card)",
                color: active ? "#fff" : "var(--ink)",
                border: "1px solid #275662",
                fontWeight: 600,
                fontFamily: '"Raleway", sans-serif',
              }}
            >
              {opt.label}
              {active && (
                <span style={{ marginLeft: 4, fontWeight: 700 }}>
                  {sortDir === "desc" ? "↓" : "↑"}
                </span>
              )}
            </button>
          );
        })}
        <span className="ml-auto text-[12px]" style={{ color: "var(--ink-muted)" }}>
          {sorted.length === 0
            ? "0 events"
            : `${startIdx + 1}–${startIdx + visible.length} of ${sorted.length} event${sorted.length !== 1 ? "s" : ""}`}
        </span>
      </div>

      <div
        className="grid gap-3"
        style={{
          gridTemplateColumns: "repeat(5, minmax(0, 1fr))",
        }}
      >
        {visible.map((e) => (
          <GalleryCard
            key={e.id}
            event={e}
            ab={ab}
            metadata={metadata}
            plateMap={plateMap}
            onPick={onPick}
            setVerdict={setVerdict}
            actionEnabled={actionEnabled}
            setAction={setAction}
          />
        ))}
      </div>

      {totalPages > 1 && (
        <Pagination
          page={safePage}
          totalPages={totalPages}
          onChange={setPage}
        />
      )}

      <p className="text-[11px] mt-6" style={{ color: "var(--ink-muted)" }}>
        Click any thumbnail to open the full view with diagnostics and verdict
        controls.
      </p>
        </>
      )}
    </div>
  );
};

/* ---------- NETWORK TAB ---------- */
